def _solve(rains):
    n = len(rains)
    BIT = [0] * (n + 2)

    def update(i, delta):
        while i <= n:
            BIT[i] += delta
            i += i & (-i)

    def prefix(i):
        s = 0
        while i > 0:
            s += BIT[i]
            i -= i & (-i)
        return s

    def find_kth(k):
        pos = 0
        logn = n.bit_length()
        for pw in range(logn, -1, -1):
            nxt = pos + (1 << pw)
            if nxt <= n and BIT[nxt] < k:
                pos = nxt
                k -= BIT[nxt]
        return pos + 1

    full = {}
    ans = [1] * n
    for i, r in enumerate(rains):
        if r > 0:
            ans[i] = -1
            if r in full:
                last = full[r]
                cnt_before = prefix(last + 1)
                total_avail = prefix(n)
                if cnt_before >= total_avail:
                    return []
                pos1 = find_kth(cnt_before + 1)
                day0 = pos1 - 1
                ans[day0] = r
                update(pos1, -1)
            full[r] = i
        else:
            update(i + 1, 1)
    return ans


def validate(args, output):
    rains = args[0]
    n = len(rains)
    if not isinstance(output, list):
        return False
    if len(output) == 0:
        return _solve(rains) == []
    if len(output) != n:
        return False
    full = set()
    for i in range(n):
        if rains[i] > 0:
            if output[i] != -1:
                return False
            if rains[i] in full:
                return False
            full.add(rains[i])
        else:
            d = output[i]
            if not isinstance(d, int) or isinstance(d, bool):
                return False
            if d in full:
                full.discard(d)
    return True

