        for (let pw = logn; pw >= 0; pw--) {
            const nxt = pos + (1 << pw);
            if (nxt <= n && BIT[nxt] < k) {
                pos = nxt;
                k -= BIT[nxt];
            }
        }
        return pos + 1;
    }
    const full = new Map();
    const ans = new Array(n).fill(1);
    for (let i = 0; i < n; i++) {
        const r = rains[i];
        if (r > 0) {
