                if (cntBefore >= totalAvail) return [];
                const pos1 = findKth(cntBefore + 1);
                const day0 = pos1 - 1;
                ans[day0] = r;
                update(pos1, -1);
            }
            full.set(r, i);
        } else {
            update(i + 1, 1);
        }
    }
    return ans;
