function validate(args, output) {
    const rains = args[0];
    const n = rains.length;
    if (!Array.isArray(output)) return false;
    if (output.length === 0) {
        return _solve(rains).length === 0;
    }
    if (output.length !== n) return false;
    const full = new Set();
    for (let i = 0; i < n; i++) {
        if (rains[i] > 0) {
            if (output[i] !== -1) return false;
            if (full.has(rains[i])) return false;
            full.add(rains[i]);
        } else {
            const d = output[i];
            if (typeof d !== 'number' || !Number.isInteger(d)) return false;
            full.delete(d);
        }
    }
    return true;
}

