import bisect


class Solution:
    def avoidFlood(self, rains):
        n = len(rains)
        full = {}
        available = []
        ans = [1] * n
        for i, r in enumerate(rains):
            if r > 0:
                ans[i] = -1
                if r in full:
                    last = full[r]
                    idx = bisect.bisect_right(available, last)
                    if idx == len(available):
                        return []
                    d = available.pop(idx)
                    ans[d] = r
                full[r] = i
            else:
                available.append(i)
        return ans

